import numpy as npimport pandas as pdfrom tqdm import tqdm# Interpolation functiondef ip_f(ts, method, order):        """        Function computing interpolation on a time-series        ts = timeseries        method = interpolation method        order = order of interpolation        """        df = pd.DataFrame(data=ts)        df.replace(0, np.nan, inplace=True) # Replace 0 by nan        ip = (df.interpolate(method=method, order=order, limit=None,                             limit_direction=None) # Interpolate              .fillna(df.interpolate(method="spline", order=1, limit=None,                                     limit_direction="both"))) # Extrapolate        ip = ip[0].values.tolist() # df to list        return ip# With save filedef write_in_chunks(f, lst, n):        """        Function saving interpolated voxel without brackets and commas        """        for i in range(0, len(lst), n):                chunk = lst[i : i+n]                f.write(" ".join(str(val) for val in chunk) + "\n")# Datasubjects = ["Subject1", "Subject2", "Subject4", "Subject5", "Subject6",            "Subject7", "Subject8", "Subject9", "Subject10", "Subject11",            "Subject12", "Subject13", "Subject14", "Subject15", "Subject16",            "Subject17", "Subject18", "Subject19"]sessions = ["awake", "sleep", "stimulus"]rois = ["limbic", "smn", "van", "visual", "dan", "fpn", "dmn", "cereb"]for subject in tqdm(subjects):        for session in sessions:                for roi in rois:                        print(f"Processing {subject} {session.title()}"                              f" {roi.title()}...")                        data = np.loadtxt("/volumes/sandisk2/fmri/dataset_3"                                          f"/processed/extracted_ts_{session}"                                          f"/{subject}/ts_{roi}_{subject}.1D")                        # Interpolation per voxel                        ip_data = []                        i = 0                        for row in data:                                i = i+1                                ip = ip_f(ts=row, method="polynomial", order=3)                                ip_data.append(ip)                        # Save interpolation                        with open("/volumes/sandisk2/fmri/dataset_3/processed"                                  f"/extracted_ts_{session}/{subject}"                                  f"/IP_TS_{roi}_{subject}.1D", "w") as file:                                # Write voxel per row                                # Remove brackets and commas from "ip_data"                                for i in ip_data:                                        write_in_chunks(file, i, len(i))